/* Element selector */
p { color: black; }

/* Class selector (dot prefix) */
.card { border: 1px solid #ccc; }

/* ID selector (hash prefix) */
#header { background: navy; }

/* Descendant selector */
nav a { text-decoration: none; }

/* Pseudo-class */
a:hover { color: red; }

/* Child combinator */
article > p { font-size: 16px; }

/* Without box-sizing (default — painful!) */
.box {
  width: 200px;
  padding: 20px;
  border: 2px solid black;
  /* Actual width = 200 + 20*2 + 2*2 = 244px !!!! */
}

/* With box-sizing (the sane way) */
.box {
  box-sizing: border-box;
  width: 200px;
  padding: 20px;
  border: 2px solid black;
  /* Actual width = 200px. Padding and border are INSIDE. */
}

/* Colors */
p {
  color: red;              /* Named color */
  color: #ff0000;          /* Hex */
  color: rgb(255, 0, 0);   /* RGB */
  color: rgba(255, 0, 0, 0.5); /* RGB with transparency */
}

/* Units */
h1 { font-size: 32px; }        /* Pixels - fixed */
p  { font-size: 1.2rem; }       /* Relative to root font size */
.box { width: 50%; }            /* Percentage of parent */
.box { width: 100vw; }          /* Viewport width */

