const requests = new Map();

function isAllowed(ip, max = 5, windowMs = 60000) {
  const now = Date.now();
  const record = requests.get(ip);

  if (!record || now - record.start > windowMs) {
    requests.set(ip, { count: 1, start: now });
    return true;
  }

  if (record.count >= max) return false;
  record.count++;
  return true;
}

