    errors.push('Name must be at least 2 characters');
  }
  if (!data.email || !data.email.includes('@')) {
    errors.push('Email must be valid');
  }
  if (!data.password || data.password.length < 8) {
    errors.push('Password must be at least 8 characters');
  }
  return errors;
}

