// Backend: Paginated GET
app.get('/api/posts', (req, res) => {
  const page = parseInt(req.query.page) || 1;
  const limit = parseInt(req.query.limit) || 10;
  const start = (page - 1) * limit;

  const sliced = posts.slice(start, start + limit);
  res.json({
    posts: sliced,
    page,
    totalPages: Math.ceil(posts.length / limit),
    total: posts.length
  });
});

// Frontend: Pagination controls
let currentPage = 1;

async function loadPosts(page = 1) {
  const res = await fetch(`/api/posts?page=${page}&limit=10`);
  const data = await res.json();
  renderPosts(data.posts);
  renderPagination(data.page, data.totalPages);
  currentPage = data.page;
}

function renderPagination(page, totalPages) {
  const controls = document.getElementById('pagination');
  controls.innerHTML = `
    <button ${page <= 1 ? 'disabled' : ''} onclick="loadPosts(${page - 1})">Previous</button>
    <span>Page ${page} of ${totalPages}</span>
    <button ${page >= totalPages ? 'disabled' : ''} onclick="loadPosts(${page + 1})">Next</button>
  `;
}

// Backend: Like endpoint
app.post('/api/posts/:id/like', auth, (req, res) => {
  const post = posts.find(p => p.id === parseInt(req.params.id));
  if (!post) return res.status(404).json({ error: 'Not found' });

  if (!post.likedBy) post.likedBy = [];

  const alreadyLiked = post.likedBy.includes(req.user.id);
  if (alreadyLiked) {
    // Unlike
    post.likedBy = post.likedBy.filter(id => id !== req.user.id);
    post.likes--;
  } else {
    // Like
    post.likedBy.push(req.user.id);
    post.likes++;
  }

  res.json({ likes: post.likes, liked: !alreadyLiked });
});

// Frontend: Like handler
async function likePost(postId) {
  const token = localStorage.getItem('token');
  const res = await fetch(`/api/posts/${postId}/like`, {
    method: 'POST',
    headers: { 'Authorization': 'Bearer ' + token }
  });
  const data = await res.json();
  if (res.ok) {
    const btn = document.getElementById(`like-${postId}`);
    btn.textContent = `❤ ${data.likes}`;
    btn.classList.toggle('liked', data.liked);
  }
}

